const tenant = $input.first().json;
const now = new Date();
// We're on Sunday (day 0). Week started last Monday (6 days ago).
const monday = new Date(now);
monday.setDate(now.getDate() - 6);
const week_start = monday.toISOString().split('T')[0];
const week_end = now.toISOString().split('T')[0]; // today = Sunday

return [{
  json: {
    tenant_id: tenant.id,
    tenant_chat_id: tenant.telegram_chat_id,
    persona_name: tenant.persona_name || 'Coach',
    tone: tenant.tone || 'direct',
    week_start,
    week_end
  }
}];

const weekBoundaries = $('Calculate Week Boundaries').item.json;
// Get all days from the HTTP request — may be array of items
const dailyItems = $('Get This Week Daily Priorities').all();
const days = dailyItems.map(i => i.json);

const previousReviews = $('Get Last 3 Weekly Reviews').all().map(i => i.json);

const daysWithScore = days.filter(d => d.execution_score !== null && d.execution_score !== undefined);
const weeklyScore = daysWithScore.length > 0
  ? daysWithScore.reduce((sum, d) => sum + d.execution_score, 0) / daysWithScore.length
  : null;

// Identify worst days (score < 50%)
const worstDays = days
  .filter(d => d.execution_score !== null && d.execution_score < 50)
  .map(d => ({
    date: d.date,
    score: d.execution_score,
    day: new Date(d.date + 'T12:00:00Z').toLocaleDateString('en-US', { weekday: 'long' })
  }));

// Build summary of daily priorities for Claude context
const dailySummary = days.map(d => {
  const completed = d.priorities ? d.priorities.filter(p => p.completed === true).length : 0;
  const total = d.priorities ? d.priorities.length : 0;
  const dayName = new Date(d.date + 'T12:00:00Z').toLocaleDateString('en-US', { weekday: 'short' });
  return `${dayName} ${d.date}: ${completed}/${total} completed (${d.execution_score !== null ? Math.round(d.execution_score) + '%' : 'no check-in'})`;
}).join('\n');

// Previous review context
const prevReviewText = previousReviews.length > 0
  ? previousReviews.map(r => `Week of ${r.week_start}: ${r.execution_score !== null ? Math.round(r.execution_score) + '%' : 'N/A'} — ${r.pattern_observation || ''}`).join('\n')
  : 'No previous weekly reviews.';

return [{
  json: {
    tenant_id: weekBoundaries.tenant_id,
    tenant_chat_id: weekBoundaries.tenant_chat_id,
    persona_name: weekBoundaries.persona_name,
    tone: weekBoundaries.tone,
    week_start: weekBoundaries.week_start,
    week_end: weekBoundaries.week_end,
    weeklyScore,
    worstDays,
    daysWithScore: daysWithScore.length,
    totalDays: days.length,
    dailySummary,
    prevReviewText
  }
}];

