const weekData = $('Calculate Weekly Score').item.json;
const claudeResponse = $('Claude — Generate Pattern Observation').item.json;
const patternText = claudeResponse.content[0].text;

const score = weekData.weeklyScore;
let scoreLabel, scoreDisplay;

if (score === null) {
  scoreDisplay = 'No data yet';
  scoreLabel = 'No check-ins recorded this week.';
} else {
  const rounded = Math.round(score);
  scoreDisplay = `${rounded}%`;
  if (rounded >= 70) {
    scoreLabel = 'Strong week.';
  } else if (rounded >= 50) {
    scoreLabel = 'Decent week.';
  } else {
    scoreLabel = 'Below target.';
  }
}

const msg = `Weekly Review — ${weekData.week_start}\n\n` +
  `Execution Score: *${scoreDisplay}* — ${scoreLabel}\n\n` +
  `${patternText}\n\n` +
  `New week starts tomorrow. What's the most important thing to do differently?`;

return [{
  json: {
    tenant_id: weekData.tenant_id,
    tenant_chat_id: weekData.tenant_chat_id,
    message: msg,
    pattern_text: patternText
  }
}];

